#include "FreeRTOS.h"
#include "task.h"
#include "semphr.h"

SemaphoreHandle_t xSemaphore;

void sensor_isr(void)
{
    // Unsafe: calls standard Give from ISR context without FromISR suffix!
    xSemaphoreGive(xSemaphore);
}

void vSensorTask(void *pvParameters)
{
    for(;;)
    {
        if(xSemaphoreTake(xSemaphore, portMAX_DELAY) == pdPASS)
        {
            // Read sensor values
        }
    }
}

int main(void)
{
    xSemaphore = xSemaphoreCreateBinary();
    // Arduino external interrupt API mismatch
    attachInterrupt(0, sensor_isr, RISING);
    xTaskCreate(vSensorTask, "Sensor", 128, NULL, 1, NULL);
    vTaskStartScheduler();
    for(;;);
}
